+// Layer norm in-place using tensor indices
+fn layerNormInPlace(hidden: []f32, seq_len: usize, weight_idx: usize, bias_idx: usize) void {
+    const eps: f32 = 1e-5;
+    for (0..seq_len) |pos| {
+        const h = hidden[pos * CLIP_EMBED_DIM ..][0..CLIP_EMBED_DIM];
+
+        // Mean
+        var mean: f32 = 0;
+        for (h) |v| mean += v;
+        mean /= CLIP_EMBED_DIM;
+
+        // Variance
+        var variance: f32 = 0;
+        for (h) |v| {
+            const diff = v - mean;
+            variance += diff * diff;
+        }
+        variance /= CLIP_EMBED_DIM;
