+        // Normalize
+        const inv_std = 1.0 / @sqrt(variance + eps);
+        for (0..CLIP_EMBED_DIM) |i| {
+            h[i] = (h[i] - mean) * inv_std * readWeight(weight_idx, i) + readWeight(bias_idx, i);
